public void removeValue(int index) {
        this.keys.remove(index);
        this.values.remove(index);
        // Always rebuild the index after a removal to keep key->index mapping consistent
        rebuildIndex();
    }

public void removeValue(Comparable key) {
        int index = getIndex(key);
        if (index < 0) {
            throw new UnknownKeyException("The key (" + key + ") is not recognised.");
        }
        removeValue(index);
    }

public void removeColumn(Comparable columnKey) {
        if (!this.columnKeys.contains(columnKey)) {
            throw new UnknownKeyException("The column key (" + columnKey + ") is not recognised.");
        }
        Iterator iterator = this.rows.iterator();
        while (iterator.hasNext()) {
            DefaultKeyedValues rowData = (DefaultKeyedValues) iterator.next();
            if (rowData.getIndex(columnKey) >= 0) {
                rowData.removeValue(columnKey);
            }
        }
        this.columnKeys.remove(columnKey);
    }

